class PriorityQueue(Generic[T]):
    """Min-heap priority queue."""

    def __init__(self) -> None:
        self._heap: list[tuple[float, int, T]] = []
        self._counter = 0
        self._lock = threading.Lock()

    def push(self, item: T, priority: float = 0.0) -> None:
        """Add an item with the given priority (lower = higher priority)."""
        with self._lock:
            import heapq
            heapq.heappush(self._heap, (priority, self._counter, item))
            self._counter += 1

    def pop(self) -> T | None:
        """Remove and return the highest-priority item."""
        with self._lock:
            if not self._heap:
                return None
            import heapq
            _, _, item = heapq.heappop(self._heap)
            return item

    def peek(self) -> T | None:
        """Return the highest-priority item without removing it."""
        with self._lock:
            if not self._heap:
                return None
            return self._heap[0][2]

    def size(self) -> int:
        with self._lock:
            return len(self._heap)

    def is_empty(self) -> bool:
        return self.size() == 0

    def clear(self) -> None:
        with self._lock:
            self._heap.clear()

    def drain(self) -> list[T]:
        """Remove and return all items in priority order."""
        with self._lock:
            import heapq
            result: list[T] = []
            while self._heap:
                _, _, item = heapq.heappop(self._heap)
                result.append(item)
            return result


class RingBuffer(Generic[T]):
    """Fixed-size circular buffer."""

    def __init__(self, capacity: int) -> None:
        if capacity <= 0:
            raise ValueError("capacity must be positive")
        self._capacity = capacity
        self._buffer: list[T | None] = [None] * capacity
        self._head = 0
        self._tail = 0
        self._size = 0
        self._lock = threading.Lock()

    def append(self, item: T) -> T | None:
        """Append an item. Returns evicted item if buffer was full."""
        with self._lock:
            evicted: T | None = None
            if self._size == self._capacity:
                evicted = self._buffer[self._head]
                self._head = (self._head + 1) % self._capacity
            else:
                self._size += 1
            self._buffer[self._tail] = item
            self._tail = (self._tail + 1) % self._capacity
            return evicted

    def get(self, index: int) -> T | None:
        """Get item at logical index (0 = oldest)."""
        with self._lock:
            if index < 0 or index >= self._size:
                return None
            actual = (self._head + index) % self._capacity
            return self._buffer[actual]

    def to_list(self) -> list[T]:
        """Return all items from oldest to newest."""
        with self._lock:
            result: list[T] = []
            for i in range(self._size):
                actual = (self._head + i) % self._capacity
                item = self._buffer[actual]
                if item is not None:
                    result.append(item)
            return result

    @property
    def capacity(self) -> int:
        return self._capacity

    def size(self) -> int:
        with self._lock:
            return self._size

    def is_full(self) -> bool:
        with self._lock:
            return self._size == self._capacity

    def is_empty(self) -> bool:
        return self.size() == 0

    def clear(self) -> None:
        with self._lock:
            self._buffer = [None] * self._capacity
            self._head = self._tail = self._size = 0


